mapper.select:
select cml.id, cml.merchant_id, cml.create_time, cml.logistic_name, cml.region, cml.charge_type, cml.weight, cml.price, cml.second_weight, cml.second_price, cml.if_default, cml.state, cmi.merchant_name as merchantName from cm_merchant_logistics cml left join cm_merchant_info cmi on cml.merchant_id = cmi.id where cml.deleted = '0' and cmi.deleted = '0'
and cml.merchant_id = #{vo.merchantId}
and cml.state = #{vo.state}
and cml.logistic_name like concat('%', #{vo.logisticName}, '%')
order by cml.create_time desc
